import React from 'react';
import "./styles.css";
import MenuBar from "../menubar/MenuBar";
import {
  Layout,
  Menu,
  Breadcrumb,
  Typography,
  Select,
  Input,
  Table,
  Badge,
  Button,
  Avatar,
  Space,
  Flex,
} from 'antd';
import type { MenuProps, TableProps } from 'antd';
import {
  DashboardOutlined,
  DesktopOutlined,
  MessageOutlined,
  FileTextOutlined,
  SettingOutlined,
  LogoutOutlined,
  BellOutlined,
  PlusOutlined,
  SearchOutlined,
  RightOutlined,
  LeftOutlined,
} from '@ant-design/icons';

const { Header, Content, Sider } = Layout;
const { Title, Text } = Typography;
const { Option } = Select;

type MenuItem = Required<MenuProps>['items'][number];

function getItem(
  label: React.ReactNode,
  key: React.Key,
  icon?: React.ReactNode,
  children?: MenuItem[],
): MenuItem {
  return {
    key,
    icon,
    children,
    label,
  } as MenuItem;
}

const menuItems: MenuItem[] = [
  getItem('Dashboard', '1', <DashboardOutlined />),
  getItem('Thiết bị', '2', <DesktopOutlined />),
  getItem('Dịch vụ', '3', <MessageOutlined />),
  getItem('Cấp số', '4', <FileTextOutlined />),
  getItem('Báo cáo', '5', <FileTextOutlined />),
  getItem('Cài đặt hệ thống', '6', <SettingOutlined />),
];

interface DataType {
  key: string;
  maThietBi: string;
  tenThietBi: string;
  diaChiIP: string;
  trangThaiHoatDong: 'Hoạt động' | 'Ngưng hoạt động';
  trangThaiKetNoi: 'Kết nối' | 'Mất kết nối';
  dichVuSuDung: string;
}

const dataSource: DataType[] = [
  { key: '1', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Ngưng hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '2', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '3', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '4', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Ngưng hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '5', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '6', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '7', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Ngưng hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '8', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
  { key: '9', maThietBi: 'KIO_01', tenThietBi: 'Kiosk', diaChiIP: '192.168.1.10', trangThaiHoatDong: 'Hoạt động', trangThaiKetNoi: 'Mất kết nối', dichVuSuDung: 'Khám tim mạch, Khám mắt...' },
];

const columns: TableProps<DataType>['columns'] = [
  { title: 'Mã thiết bị', dataIndex: 'maThietBi', key: 'maThietBi' },
  { title: 'Tên thiết bị', dataIndex: 'tenThietBi', key: 'tenThietBi' },
  { title: 'Địa chỉ IP', dataIndex: 'diaChiIP', key: 'diaChiIP' },
  {
    title: 'Trạng thái hoạt động',
    dataIndex: 'trangThaiHoatDong',
    key: 'trangThaiHoatDong',
    render: (text) => (
      <Badge
        status={text === 'Hoạt động' ? 'success' : 'error'}
        text={text}
      />
    ),
  },
  {
    title: 'Trạng thái kết nối',
    dataIndex: 'trangThaiKetNoi',
    key: 'trangThaiKetNoi',
    render: (text) => (
      <Badge
        status={text === 'Kết nối' ? 'success' : 'error'}
        text={text}
      />
    ),
  },
  {
    title: 'Dịch vụ sử dụng',
    dataIndex: 'dichVuSuDung',
    key: 'dichVuSuDung',
    render: (text) => (
      <div>
        {text}
        <br />
        <a href="services.tsx">Xem thêm</a>
      </div>
    ),
    width: 250,
  },
  {
    title: '',
    key: 'actionDetail',
    render: () => <a href="service_detail.tsx">Chi tiết</a>,
  },
  {
    title: '',
    key: 'actionUpdate',
    render: () => <a href="service_update.tsx">Cập nhật</a>,
  },
];

const Device = () => {
    return (
        <Layout style={{ minHeight: '100vh', backgroundColor: '#F6F6F6' }}>
              
            </Layout>
    )
};

export default Device;
